
INSERT INTO t_p37480106_simple_news_rss_star.news_items
  (source_id, guid, title, excerpt, title_ru, excerpt_ru, translated, url, image_url, category, published_at)
VALUES

(2, 'seed-ru-001', 'GTA VI выйдет осенью 2025: Rockstar подтвердила дату релиза', 'Rockstar Games официально анонсировала дату выхода Grand Theft Auto VI — игра поступит в продажу 26 сентября 2025 года на PlayStation 5 и Xbox Series X/S. PC-версия появится позже.', 'GTA VI выйдет осенью 2025: Rockstar подтвердила дату релиза', 'Rockstar Games официально анонсировала дату выхода Grand Theft Auto VI — игра поступит в продажу 26 сентября 2025 года на PlayStation 5 и Xbox Series X/S. PC-версия появится позже.', true, 'https://gamefeed.ru/news/1', 'https://cdn.poehali.dev/projects/973edfaa-a323-4093-b6b0-33c1214206be/files/af879cd1-5927-43f0-8fbc-8e46fe0e0265.jpg', 'Консоли', NOW() - INTERVAL '2 hours'),

(2, 'seed-ru-002', 'Elden Ring 2 официально анонсирован: FromSoftware работает над сиквелом', 'На Summer Game Fest студия FromSoftware показала первый трейлер продолжения Elden Ring. Новая игра создаётся в соавторстве с Джорджем Мартином и обещает ещё более масштабный открытый мир с переработанной боевой системой.', 'Elden Ring 2 официально анонсирован: FromSoftware работает над сиквелом', 'На Summer Game Fest студия FromSoftware показала первый трейлер продолжения Elden Ring. Новая игра создаётся в соавторстве с Джорджем Мартином и обещает ещё более масштабный открытый мир с переработанной боевой системой.', true, 'https://gamefeed.ru/news/2', 'https://cdn.poehali.dev/projects/973edfaa-a323-4093-b6b0-33c1214206be/files/6871d83a-8d84-4793-9df6-8bcea0ae44e8.jpg', 'RPG', NOW() - INTERVAL '4 hours'),

(2, 'seed-ru-003', 'CS2 — крупнейший патч года меняет экономику и карту Dust2', 'Valve выпустила масштабное обновление для CS2: полностью переработана экономическая система, карта Dust2 получила визуальный редизайн, а система анти-чита Valve Anti-Cheat обновлена до шестой версии.', 'CS2 — крупнейший патч года меняет экономику и карту Dust2', 'Valve выпустила масштабное обновление для CS2: полностью переработана экономическая система, карта Dust2 получила визуальный редизайн, а система анти-чита Valve Anti-Cheat обновлена до шестой версии.', true, 'https://gamefeed.ru/news/3', '', 'Шутеры', NOW() - INTERVAL '6 hours'),

(2, 'seed-ru-004', 'Team Spirit выиграла The International 2025 с призом $18 млн', 'Российская команда Team Spirit стала чемпионом мира по Dota 2 на турнире The International 2025. В финале они обыграли китайский состав PSG.LGD со счётом 3:1. Общий призовой фонд турнира составил рекордные $40 млн.', 'Team Spirit выиграла The International 2025 с призом $18 млн', 'Российская команда Team Spirit стала чемпионом мира по Dota 2 на турнире The International 2025. В финале они обыграли китайский состав PSG.LGD со счётом 3:1. Общий призовой фонд турнира составил рекордные $40 млн.', true, 'https://gamefeed.ru/news/4', 'https://cdn.poehali.dev/projects/973edfaa-a323-4093-b6b0-33c1214206be/files/6c3a6321-c3ef-4f09-86f0-7e2fae796585.jpg', 'Киберспорт', NOW() - INTERVAL '8 hours'),

(2, 'seed-ru-005', 'Hollow Knight: Silksong — новый трейлер и дата выхода 14 марта', 'После многолетнего ожидания Team Cherry наконец раскрыла дату релиза Hollow Knight: Silksong. Игра выйдет 14 марта 2026 года на PC, Nintendo Switch и Xbox. В новом трейлере показаны свежие локации и способности героини Хорнет.', 'Hollow Knight: Silksong — новый трейлер и дата выхода 14 марта', 'После многолетнего ожидания Team Cherry наконец раскрыла дату релиза Hollow Knight: Silksong. Игра выйдет 14 марта 2026 года на PC, Nintendo Switch и Xbox. В новом трейлере показаны свежие локации и способности героини Хорнет.', true, 'https://gamefeed.ru/news/5', '', 'Инди', NOW() - INTERVAL '10 hours'),

(2, 'seed-ru-006', 'Baldur''s Gate 3 получит бесплатное дополнение с новым актом', 'Larian Studios объявила о разработке бесплатного обновления для Baldur''s Gate 3, которое добавит эпилог к основной истории и новые взаимодействия с компаньонами. Обновление выйдет для всех владельцев игры этим летом.', 'Baldur''s Gate 3 получит бесплатное дополнение с новым актом', 'Larian Studios объявила о разработке бесплатного обновления для Baldur''s Gate 3, которое добавит эпилог к основной истории и новые взаимодействия с компаньонами. Обновление выйдет для всех владельцев игры этим летом.', true, 'https://gamefeed.ru/news/6', 'https://cdn.poehali.dev/projects/973edfaa-a323-4093-b6b0-33c1214206be/files/6871d83a-8d84-4793-9df6-8bcea0ae44e8.jpg', 'RPG', NOW() - INTERVAL '12 hours'),

(2, 'seed-ru-007', 'Minecraft получит глобальный ребрендинг и новый движок в 2026 году', 'Microsoft объявила о масштабном обновлении Minecraft: игра перейдёт на новый движок с улучшенной графикой, поддержкой трассировки лучей и кроссплатформенным мультиплеером между всеми платформами без исключения.', 'Minecraft получит глобальный ребрендинг и новый движок в 2026 году', 'Microsoft объявила о масштабном обновлении Minecraft: игра перейдёт на новый движок с улучшенной графикой, поддержкой трассировки лучей и кроссплатформенным мультиплеером между всеми платформами без исключения.', true, 'https://gamefeed.ru/news/7', '', 'PC', NOW() - INTERVAL '14 hours'),

(2, 'seed-ru-008', 'Naughty Dog анонсировала новую одиночную игру — не The Last of Us', 'Студия Naughty Dog официально подтвердила работу над совершенно новой франшизой. Игра не связана ни с The Last of Us, ни с Uncharted. По словам разработчиков, проект будет «самым амбициозным в истории студии».', 'Naughty Dog анонсировала новую одиночную игру — не The Last of Us', 'Студия Naughty Dog официально подтвердила работу над совершенно новой франшизой. Игра не связана ни с The Last of Us, ни с Uncharted. По словам разработчиков, проект будет «самым амбициозным в истории студии».', true, 'https://gamefeed.ru/news/8', 'https://cdn.poehali.dev/projects/973edfaa-a323-4093-b6b0-33c1214206be/files/af879cd1-5927-43f0-8fbc-8e46fe0e0265.jpg', 'Консоли', NOW() - INTERVAL '18 hours'),

(2, 'seed-ru-009', 'Cyberpunk 2077 — патч 2.5 добавляет новый район и 15 часов контента', 'CD Projekt Red выпустила патч 2.5 для Cyberpunk 2077, который добавляет новый район Найт-Сити — Северный Уотсон, 15 часов новых заданий, переработанную систему транспорта и поддержку DLSS 4 с мультикадровой генерацией.', 'Cyberpunk 2077 — патч 2.5 добавляет новый район и 15 часов контента', 'CD Projekt Red выпустила патч 2.5 для Cyberpunk 2077, который добавляет новый район Найт-Сити — Северный Уотсон, 15 часов новых заданий, переработанную систему транспорта и поддержку DLSS 4 с мультикадровой генерацией.', true, 'https://gamefeed.ru/news/9', 'https://cdn.poehali.dev/projects/973edfaa-a323-4093-b6b0-33c1214206be/files/af879cd1-5927-43f0-8fbc-8e46fe0e0265.jpg', 'Обновления', NOW() - INTERVAL '20 hours'),

(2, 'seed-ru-010', 'Nintendo Switch 2 поступает в продажу: первые впечатления прессы', 'Nintendo Switch 2 официально поступила в магазины. Журналисты отмечают значительно улучшенную производительность, 4K в режиме стационарной консоли, новый магнитный Joy-Con и обратную совместимость со всеми играми первого Switch.', 'Nintendo Switch 2 поступает в продажу: первые впечатления прессы', 'Nintendo Switch 2 официально поступила в магазины. Журналисты отмечают значительно улучшенную производительность, 4K в режиме стационарной консоли, новый магнитный Joy-Con и обратную совместимость со всеми играми первого Switch.', true, 'https://gamefeed.ru/news/10', 'https://cdn.poehali.dev/projects/973edfaa-a323-4093-b6b0-33c1214206be/files/6c3a6321-c3ef-4f09-86f0-7e2fae796585.jpg', 'Консоли', NOW() - INTERVAL '22 hours'),

(2, 'seed-ru-011', 'Valorant — новый агент Призрак кардинально меняет мету', 'Riot Games представила нового агента для Valorant — Призрак. Его уникальная механика позволяет временно становиться невидимым для камер и дронов противника. По словам разработчиков, агент создан специально для любителей стелс-тактик.', 'Valorant — новый агент Призрак кардинально меняет мету', 'Riot Games представила нового агента для Valorant — Призрак. Его уникальная механика позволяет временно становиться невидимым для камер и дронов противника. По словам разработчиков, агент создан специально для любителей стелс-тактик.', true, 'https://gamefeed.ru/news/11', '', 'Шутеры', NOW() - INTERVAL '26 hours'),

(2, 'seed-ru-012', 'The Witcher 4 — показан первый геймплей с открытым миром', 'CD Projekt Red представила первые 12 минут геймплея The Witcher 4. Главная героиня Цирилла исследует новый континент Эльден-Скар. Движок REDengine 5 демонстрирует фотореалистичную графику и динамическую погоду в реальном времени.', 'The Witcher 4 — показан первый геймплей с открытым миром', 'CD Projekt Red представила первые 12 минут геймплея The Witcher 4. Главная героиня Цирилла исследует новый континент Эльден-Скар. Движок REDengine 5 демонстрирует фотореалистичную графику и динамическую погоду в реальном времени.', true, 'https://gamefeed.ru/news/12', 'https://cdn.poehali.dev/projects/973edfaa-a323-4093-b6b0-33c1214206be/files/6871d83a-8d84-4793-9df6-8bcea0ae44e8.jpg', 'RPG', NOW() - INTERVAL '30 hours'),

(2, 'seed-ru-013', 'Steam установил новый рекорд — 40 млн одновременных пользователей', 'Valve сообщила о новом рекорде одновременных пользователей в Steam: платформу одновременно посещали более 40 миллионов человек. Прошлый рекорд в 37 млн был установлен в январе 2024 года.', 'Steam установил новый рекорд — 40 млн одновременных пользователей', 'Valve сообщила о новом рекорде одновременных пользователей в Steam: платформу одновременно посещали более 40 миллионов человек. Прошлый рекорд в 37 млн был установлен в январе 2024 года.', true, 'https://gamefeed.ru/news/13', '', 'PC', NOW() - INTERVAL '34 hours'),

(2, 'seed-ru-014', 'Starfield — дополнение «Шрам» добавляет новую планету и 20 часов сюжета', 'Bethesda выпустила второе крупное дополнение для Starfield под названием «Шрам». Игроков ждёт загадочная планета Кальдера, населённая выжившими из потерянной колонии, новые корабли и переработанная система крафта снаряжения.', 'Starfield — дополнение «Шрам» добавляет новую планету и 20 часов сюжета', 'Bethesda выпустила второе крупное дополнение для Starfield под названием «Шрам». Игроков ждёт загадочная планета Кальдера, населённая выжившими из потерянной колонии, новые корабли и переработанная система крафта снаряжения.', true, 'https://gamefeed.ru/news/14', 'https://cdn.poehali.dev/projects/973edfaa-a323-4093-b6b0-33c1214206be/files/6c3a6321-c3ef-4f09-86f0-7e2fae796585.jpg', 'RPG', NOW() - INTERVAL '38 hours'),

(2, 'seed-ru-015', 'Apex Legends переходит на модель платной игры с базовым контентом', 'Respawn Entertainment объявила об изменении бизнес-модели Apex Legends: игра станет условно-бесплатной с платным базовым набором за $19.99, включающим 10 легенд и стартовый боевой пропуск. Смена модели вступит в силу с сезона 25.', 'Apex Legends переходит на модель платной игры с базовым контентом', 'Respawn Entertainment объявила об изменении бизнес-модели Apex Legends: игра станет условно-бесплатной с платным базовым набором за $19.99, включающим 10 легенд и стартовый боевой пропуск. Смена модели вступит в силу с сезона 25.', true, 'https://gamefeed.ru/news/15', '', 'Шутеры', NOW() - INTERVAL '42 hours'),

(2, 'seed-ru-016', 'Indie World: анонсированы 15 новых инди-игр для Nintendo Switch 2', 'На Nintendo Indie World Showcase были анонсированы 15 новых инди-проектов для Switch 2. Среди них выделяются Celeste 2, духовный наследник Katana Zero и атмосферный хоррор от создателей Limbo.', 'Indie World: анонсированы 15 новых инди-игр для Nintendo Switch 2', 'На Nintendo Indie World Showcase были анонсированы 15 новых инди-проектов для Switch 2. Среди них выделяются Celeste 2, духовный наследник Katana Zero и атмосферный хоррор от создателей Limbo.', true, 'https://gamefeed.ru/news/16', '', 'Инди', NOW() - INTERVAL '46 hours'),

(2, 'seed-ru-017', 'League of Legends — полный визуальный редизайн клиента и новый сезон', 'Riot Games обновила клиент League of Legends: новый интерфейс, переработанная система рейтинга, улучшенный подбор игроков и интеграция с мобильным приложением. Обновление стартует вместе с 16-м сезоном.', 'League of Legends — полный визуальный редизайн клиента и новый сезон', 'Riot Games обновила клиент League of Legends: новый интерфейс, переработанная система рейтинга, улучшенный подбор игроков и интеграция с мобильным приложением. Обновление стартует вместе с 16-м сезоном.', true, 'https://gamefeed.ru/news/17', 'https://cdn.poehali.dev/projects/973edfaa-a323-4093-b6b0-33c1214206be/files/6c3a6321-c3ef-4f09-86f0-7e2fae796585.jpg', 'Киберспорт', NOW() - INTERVAL '50 hours'),

(2, 'seed-ru-018', 'Red Dead Redemption 3 в разработке — Rockstar нанимает сотрудников', 'В профилях LinkedIn сотрудников Rockstar Games появились упоминания нового проекта в сеттинге дикого запада. Аналитики уверены: компания работает над Red Dead Redemption 3. Официального подтверждения пока нет.', 'Red Dead Redemption 3 в разработке — Rockstar нанимает сотрудников', 'В профилях LinkedIn сотрудников Rockstar Games появились упоминания нового проекта в сеттинге дикого запада. Аналитики уверены: компания работает над Red Dead Redemption 3. Официального подтверждения пока нет.', true, 'https://gamefeed.ru/news/18', 'https://cdn.poehali.dev/projects/973edfaa-a323-4093-b6b0-33c1214206be/files/af879cd1-5927-43f0-8fbc-8e46fe0e0265.jpg', 'Консоли', NOW() - INTERVAL '55 hours'),

(2, 'seed-ru-019', 'PUBG Mobile преодолела отметку в 1 миллиард скачиваний', 'Krafton объявила, что PUBG Mobile была загружена более 1 миллиарда раз по всему миру. В честь юбилея разработчики анонсировали масштабное обновление с новой картой, режимом зомби и эксклюзивными наградами для всех игроков.', 'PUBG Mobile преодолела отметку в 1 миллиард скачиваний', 'Krafton объявила, что PUBG Mobile была загружена более 1 миллиарда раз по всему миру. В честь юбилея разработчики анонсировали масштабное обновление с новой картой, режимом зомби и эксклюзивными наградами для всех игроков.', true, 'https://gamefeed.ru/news/19', '', 'Мобильные', NOW() - INTERVAL '60 hours'),

(2, 'seed-ru-020', 'Diablo IV — сезон 8 «Проклятие Нефалемов» стартует 28 июня', 'Blizzard анонсировала восьмой сезон Diablo IV. Новый сезон «Проклятие Нефалемов» добавит класс Некроманта в переработанном виде, новый эндгейм-контент Башня Хаоса и масштабные изменения баланса всех классов.', 'Diablo IV — сезон 8 «Проклятие Нефалемов» стартует 28 июня', 'Blizzard анонсировала восьмой сезон Diablo IV. Новый сезон «Проклятие Нефалемов» добавит класс Некроманта в переработанном виде, новый эндгейм-контент Башня Хаоса и масштабные изменения баланса всех классов.', true, 'https://gamefeed.ru/news/20', 'https://cdn.poehali.dev/projects/973edfaa-a323-4093-b6b0-33c1214206be/files/6871d83a-8d84-4793-9df6-8bcea0ae44e8.jpg', 'RPG', NOW() - INTERVAL '65 hours'),

(2, 'seed-ru-021', 'Half-Life 3 — утечка исходного кода подтверждает разработку', 'В сети появился фрагмент исходного кода, предположительно принадлежащий Half-Life 3. Valve пока не комментирует ситуацию, однако несколько бывших сотрудников компании косвенно подтвердили подлинность материалов.', 'Half-Life 3 — утечка исходного кода подтверждает разработку', 'В сети появился фрагмент исходного кода, предположительно принадлежащий Half-Life 3. Valve пока не комментирует ситуацию, однако несколько бывших сотрудников компании косвенно подтвердили подлинность материалов.', true, 'https://gamefeed.ru/news/21', '', 'PC', NOW() - INTERVAL '70 hours'),

(2, 'seed-ru-022', 'Civilization VII: патч 1.2 исправляет дипломатию и добавляет русских', 'Firaxis выпустила патч 1.2 для Civilization VII. Главные изменения: полностью переработанная дипломатическая система, добавление российской цивилизации с уникальными юнитами Стрельцы и Опричники, а также исправление более 300 ошибок.', 'Civilization VII: патч 1.2 исправляет дипломатию и добавляет русских', 'Firaxis выпустила патч 1.2 для Civilization VII. Главные изменения: полностью переработанная дипломатическая система, добавление российской цивилизации с уникальными юнитами Стрельцы и Опричники, а также исправление более 300 ошибок.', true, 'https://gamefeed.ru/news/22', 'https://cdn.poehali.dev/projects/973edfaa-a323-4093-b6b0-33c1214206be/files/6c3a6321-c3ef-4f09-86f0-7e2fae796585.jpg', 'Стратегии', NOW() - INTERVAL '75 hours'),

(2, 'seed-ru-023', 'Sony анонсировала PlayStation 6 с поддержкой 8K и нейросетевым апскейлингом', 'Sony Interactive Entertainment официально анонсировала PlayStation 6. Консоль получит поддержку 8K-разрешения, аппаратное ускорение трассировки лучей нового поколения и встроенный нейросетевой чип для апскейлинга изображения в реальном времени.', 'Sony анонсировала PlayStation 6 с поддержкой 8K и нейросетевым апскейлингом', 'Sony Interactive Entertainment официально анонсировала PlayStation 6. Консоль получит поддержку 8K-разрешения, аппаратное ускорение трассировки лучей нового поколения и встроенный нейросетевой чип для апскейлинга изображения в реальном времени.', true, 'https://gamefeed.ru/news/23', 'https://cdn.poehali.dev/projects/973edfaa-a323-4093-b6b0-33c1214206be/files/af879cd1-5927-43f0-8fbc-8e46fe0e0265.jpg', 'Консоли', NOW() - INTERVAL '80 hours'),

(2, 'seed-ru-024', 'Escape from Tarkov выходит из раннего доступа после 8 лет разработки', 'Battlestate Games объявила о выходе Escape from Tarkov из стадии раннего доступа. Финальная версия 1.0 включает все запланированные локации, переработанный сюжетный режим и кооперативные рейды на 16 игроков.', 'Escape from Tarkov выходит из раннего доступа после 8 лет разработки', 'Battlestate Games объявила о выходе Escape from Tarkov из стадии раннего доступа. Финальная версия 1.0 включает все запланированные локации, переработанный сюжетный режим и кооперативные рейды на 16 игроков.', true, 'https://gamefeed.ru/news/24', '', 'Шутеры', NOW() - INTERVAL '90 hours'),

(2, 'seed-ru-025', 'Hades II вышла из раннего доступа с полной версией и новым финалом', 'Supergiant Games выпустила финальную версию Hades II. В полном релизе добавлен второй игровой персонаж — Мелинойя, новые биомы Олимпа, расширенный саундтрек и альтернативная концовка, открывающаяся после прохождения игры несколько раз.', 'Hades II вышла из раннего доступа с полной версией и новым финалом', 'Supergiant Games выпустила финальную версию Hades II. В полном релизе добавлен второй игровой персонаж — Мелинойя, новые биомы Олимпа, расширенный саундтрек и альтернативная концовка, открывающаяся после прохождения игры несколько раз.', true, 'https://gamefeed.ru/news/25', 'https://cdn.poehali.dev/projects/973edfaa-a323-4093-b6b0-33c1214206be/files/6871d83a-8d84-4793-9df6-8bcea0ae44e8.jpg', 'Инди', NOW() - INTERVAL '96 hours'),

(2, 'seed-ru-026', 'World of Warcraft: новое расширение «Вечный Пламень» бьёт рекорды подписок', 'Blizzard сообщила, что новое расширение World of Warcraft «Вечный Пламень» привлекло 4,5 миллиона новых подписчиков за первый месяц — лучший результат со времён Legion. Новый континент и система наследия классов получили высокие оценки игроков.', 'World of Warcraft: новое расширение «Вечный Пламень» бьёт рекорды подписок', 'Blizzard сообщила, что новое расширение World of Warcraft «Вечный Пламень» привлекло 4,5 миллиона новых подписчиков за первый месяц — лучший результат со времён Legion. Новый континент и система наследия классов получили высокие оценки игроков.', true, 'https://gamefeed.ru/news/26', '', 'RPG', NOW() - INTERVAL '100 hours'),

(2, 'seed-ru-027', 'NVIDIA представила GeForce RTX 5090 — самая мощная игровая карта в истории', 'NVIDIA анонсировала флагманскую видеокарту GeForce RTX 5090 на архитектуре Blackwell. Карта обеспечивает 120 fps в 4K при максимальных настройках в любой современной игре и поддерживает DLSS 5 с генерацией сразу нескольких кадров.', 'NVIDIA представила GeForce RTX 5090 — самая мощная игровая карта в истории', 'NVIDIA анонсировала флагманскую видеокарту GeForce RTX 5090 на архитектуре Blackwell. Карта обеспечивает 120 fps в 4K при максимальных настройках в любой современной игре и поддерживает DLSS 5 с генерацией сразу нескольких кадров.', true, 'https://gamefeed.ru/news/27', 'https://cdn.poehali.dev/projects/973edfaa-a323-4093-b6b0-33c1214206be/files/6c3a6321-c3ef-4f09-86f0-7e2fae796585.jpg', 'PC', NOW() - INTERVAL '110 hours'),

(2, 'seed-ru-028', 'Among Us 2 анонсирован с трёхмерной графикой и новыми ролями', 'Innersloth объявила о разработке Among Us 2. Сиквел получит полноценную 3D-графику, 15 новых ролей для предателей и мирных жителей, голосовой чат с детектором лжи и кросс-платформенную игру между всеми устройствами.', 'Among Us 2 анонсирован с трёхмерной графикой и новыми ролями', 'Innersloth объявила о разработке Among Us 2. Сиквел получит полноценную 3D-графику, 15 новых ролей для предателей и мирных жителей, голосовой чат с детектором лжи и кросс-платформенную игру между всеми устройствами.', true, 'https://gamefeed.ru/news/28', '', 'Мобильные', NOW() - INTERVAL '120 hours'),

(2, 'seed-ru-029', 'Обзор Avowed: лучшая RPG Obsidian со времён New Vegas', 'Avowed от Obsidian Entertainment вышла и уже собирает восторженные отзывы. Игра предлагает живой мир Эора из Pillars of Eternity, отличную боевую систему от первого лица и нелинейные квесты с настоящими последствиями выборов. Оценка прессы — 9/10.', 'Обзор Avowed: лучшая RPG Obsidian со времён New Vegas', 'Avowed от Obsidian Entertainment вышла и уже собирает восторженные отзывы. Игра предлагает живой мир Эора из Pillars of Eternity, отличную боевую систему от первого лица и нелинейные квесты с настоящими последствиями выборов. Оценка прессы — 9/10.', true, 'https://gamefeed.ru/news/29', 'https://cdn.poehali.dev/projects/973edfaa-a323-4093-b6b0-33c1214206be/files/6871d83a-8d84-4793-9df6-8bcea0ae44e8.jpg', 'RPG', NOW() - INTERVAL '130 hours'),

(2, 'seed-ru-030', 'Fortnite сезон 12 — коллаборация с Marvel и новая механика строительства', 'Epic Games запустила 12-й сезон Fortnite с масштабной коллаборацией с Marvel: в игре появились Человек-паук, Тор и Капитан Марвел в качестве игровых персонажей. Также полностью переработана механика строительства с новым режимом Zero Build Pro.', 'Fortnite сезон 12 — коллаборация с Marvel и новая механика строительства', 'Epic Games запустила 12-й сезон Fortnite с масштабной коллаборацией с Marvel: в игре появились Человек-паук, Тор и Капитан Марвел в качестве игровых персонажей. Также полностью переработана механика строительства с новым режимом Zero Build Pro.', true, 'https://gamefeed.ru/news/30', 'https://cdn.poehali.dev/projects/973edfaa-a323-4093-b6b0-33c1214206be/files/af879cd1-5927-43f0-8fbc-8e46fe0e0265.jpg', 'Шутеры', NOW() - INTERVAL '140 hours');
